const p = msg.payload;
if (!p || typeof p !== 'object') return null;

// 1) Full document for any consumer that wants it
flow.set('bms_latest', p);
flow.set('bms_latest_at', Math.floor(Date.now() / 1000));

// 2) Project-specific mapping into the global telemetry the dashboard
//    composer (fn_assemble) already reads. We only touch the bms-derived
//    keys; everything else stays as set by the other handlers.
const t = global.get('telemetry') || {};
if (typeof p.soc_pct    === 'number') t.house_battery_percent = p.soc_pct;
if (typeof p.voltage_v  === 'number') t.house_battery_voltage = p.voltage_v;
if (typeof p.current_a  === 'number') t.house_battery_current = p.current_a;
if (typeof p.power_w    === 'number') t.house_battery_power   = p.power_w;
global.set('telemetry', t);

// 3) Status badge
const soc = p.soc_pct, v = p.voltage_v, i = p.current_a;
node.status({
    fill:  p.protection_active ? 'red' : 'green',
    shape: 'dot',
    text:  `${soc}% ${v}V ${i >= 0 ? '+' : ''}${i}A @ ${new Date().toLocaleTimeString()}`
});
return msg;

const status = (typeof msg.payload === 'string') ? msg.payload : 'unknown';
flow.set('bms_status', status);
node.status({
    fill:  status === 'online' ? 'green' : 'red',
    shape: 'dot',
    text:  status
});
if (status !== 'online') {
    // bridge is down — wipe the live BMS fields from telemetry so the
    // dashboard doesn't show stale values; fn_assemble will emit nulls.
    const t = global.get('telemetry') || {};
    delete t.house_battery_percent;
    delete t.house_battery_voltage;
    delete t.house_battery_current;
    delete t.house_battery_power;
    global.set('telemetry', t);
}
return null;
